import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-navbar',
  standalone: true,
  imports: [CommonModule, RouterLink, RouterLinkActive],
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.scss']
})
export class NavbarComponent {
  constructor(public authService: AuthService) {}

  login() {
    this.authService.getLoginUrl().subscribe({
      next: (res) => {
        if (res && res.url) {
          window.location.href = res.url;
        }
      },
      error: (err) => {
        console.error('Error al obtener la URL de inicio de sesión:', err);
      }
    });
  }

  logout() {
    this.authService.logout();
  }
}
<nav class="navbar">
  <div class="navbar-inner">
    <!-- Brand Section -->
    <a routerLink="/" class="navbar-brand">
      <div class="brand-icon">
        <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" class="brand-svg">
          <path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z" fill="url(#navbar-bolt-gradient)" />
          <defs>
            <linearGradient id="navbar-bolt-gradient" x1="3" y1="2" x2="21" y2="22" gradientUnits="userSpaceOnUse">
              <stop stop-color="#FF6B35"/>
              <stop offset="1" stop-color="#F7C948"/>
            </linearGradient>
          </defs>
        </svg>
      </div>
      <div class="brand-text">
        <span class="brand-name">SmashRank</span>
        <span class="brand-subtitle">Regional Tournament Calculator</span>
      </div>
    </a>

    <!-- Navigation links -->
    <div class="navbar-links">
      <a routerLink="/" routerLinkActive="active" [routerLinkActiveOptions]="{exact: true}" class="nav-link">Inicio</a>
      <a routerLink="/ranking" routerLinkActive="active" class="nav-link">Ranking</a>
    </div>

    <!-- Auth Section -->
    <div class="navbar-auth">
      <!-- NOT logged in -->
      <button *ngIf="!authService.isLoggedIn()" (click)="login()" class="login-btn">
        <svg class="login-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
          <path stroke-linecap="round" stroke-linejoin="round" d="M15.75 6a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0zM4.501 20.118a7.5 7.5 0 0114.998 0A17.933 17.933 0 0112 21.75c-2.676 0-5.216-.584-7.499-1.632z" />
        </svg>
        <span>Conectar Start.gg</span>
      </button>

      <!-- logged in -->
      <div *ngIf="authService.isLoggedIn()" class="user-menu">
        <div class="user-profile">
          <div class="user-avatar-wrapper">
            <img *ngIf="authService.currentUser()?.avatarUrl; else defaultAvatar" [src]="authService.currentUser()?.avatarUrl" class="user-avatar" alt="Avatar">
            <ng-template #defaultAvatar>
              <div class="user-avatar-default">
                {{ authService.currentUser()?.gamerTag?.slice(0, 2)?.toUpperCase() }}
              </div>
            </ng-template>
            <span class="status-indicator"></span>
          </div>
          <div class="user-details">
            <span class="user-tag">{{ authService.currentUser()?.gamerTag }}</span>
            <span class="user-role" [ngClass]="{'user-role--admin': authService.isAdmin()}">
              {{ authService.currentUser()?.role }}
            </span>
          </div>
        </div>
        <button (click)="logout()" class="logout-btn" title="Cerrar Sesión">
          <svg class="logout-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M15.75 9V5.25A2.25 2.25 0 0013.5 3h-6a2.25 2.25 0 00-2.25 2.25v13.5A2.25 2.25 0 007.5 21h6a2.25 2.25 0 002.25-2.25V15M19 12H9m10 0l-3-3m3 3l-3 3" />
          </svg>
        </button>
      </div>
    </div>
  </div>
</nav>
